mapper.select:
SELECT COALESCE(MAX(version_no), 0)
FROM ai_agent_snapshot
WHERE agent_id = #{agentId}

mapper.delete:
DELETE FROM ai_agent_snapshot
WHERE agent_id = #{agentId}
  AND id NOT IN (
      SELECT id
      FROM (
          SELECT id
          FROM ai_agent_snapshot
          WHERE agent_id = #{agentId}
          ORDER BY version_no DESC
          LIMIT #{keepLimit}
      ) retained_snapshots
  )
